fn test_config_defaults() {
    let empty = serde_yaml::Value::Mapping(serde_yaml::Mapping::new());
    let config = from_workflow(&empty).expect("empty config should produce spec §5.3 defaults");

    assert_eq!(config.tracker.kind, None);
